export const PAYMENT_METHODS = {
  CARD: { id: 'card', name: 'Credit/Debit Card', description: 'Instant processing' },
  BANK: { id: 'bank', name: 'Bank Transfer', description: '1-2 business days' },
  CRYPTO: { id: 'crypto', name: 'Cryptocurrency', description: 'Network dependent' }
};

export const WITHDRAW_METHODS = {
  BANK: { id: 'bank', name: 'Bank Account', estimatedDays: '2-3' },
  CARD: { id: 'card', name: 'Original Card', estimatedDays: '1-2' }
};

export const validateAmount = (amount, options = {}) => {
  const { min = 0, max = Infinity, currency = 'USD', isWithdraw = false } = options;
  const numAmount = parseFloat(amount);
  
  if (!amount || isNaN(numAmount)) {
    return { valid: false, error: 'Please enter a valid amount' };
  }
  if (numAmount < min) {
    return { valid: false, error: `Minimum ${isWithdraw ? 'withdraw' : 'deposit'} is ${currency} ${min}` };
  }
  if (numAmount > max) {
    return { valid: false, error: `Maximum ${isWithdraw ? 'withdraw' : 'deposit'} is ${currency} ${max.toLocaleString()}` };
  }
  return { valid: true };
};

export const validateAccount = (account) => {
  const { accountNumber, accountName, bankName } = account;
  
  if (!accountNumber || accountNumber.replace(/\s/g, '').length < 10) {
    return { valid: false, error: 'Please enter a valid account number' };
  }
  if (!accountName || accountName.trim().length < 2) {
    return { valid: false, error: 'Please enter the account holder name' };
  }
  if (!bankName || bankName.trim().length < 2) {
    return { valid: false, error: 'Please enter the bank name' };
  }
  return { valid: true };
};
